368→export const updateJournalService = async(content, title, journalId, userId) => {
369→    if(!journalId){
370→        console.error('journalid is undefined');
371→        throw {status: 400, error: 'journalId is undefined'}
372→    }
373→
374→    if(!userId){
375→        console.error('userId is undefined')
376→        throw({status: 400, error: 'userId is undefined'})
377→    }
378→
379→    const {data: existingJournal, error: existingJournalError} = await supabase
380→    .from('journals')
381→    .select('id, user_id, content, title, post_type')
