276→    const {userId, loggedInUserId} = req.query;
277→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
278→    // console.log(req.query)
279→    try {
280→        const followersCountPromise = supabase
281→        .from('follows')
282→        .select('*', {count: 'exact', head: true})
283→        .eq('following_id', userId);
284→
285→        const followingCountPromise = supabase
286→        .from('follows')
287→        .select('*', {count: 'exact', head: true})
288→        .eq('follower_id', userId)
