294→        .eq('following_id', userId)
295→
296→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
297→            followersCountPromise, followingCountPromise, isFollowingPromise,
298→        ])
299→
300→
301→        const {count: followersCount, error: errorFollowers } = followersCountResult;
302→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
303→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
304→
305→        if(errorFollowers || errorFollowings || errorIsfollowing){
306→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
307→            return res.status(500).json({error: 'failed to fetch data'})
308→        }
309→
310→        return res.status(200).json({
311→            followersCount: followersCount,
312→            followingsCount: followingsCount,
313→            isFollowing: isFollowingCount > 0
314→        })
315→
316→    } catch (error) {
317→        console.error('Error in Promise.all:', error);
318→        res.status(500).json({ error: 'An unexpected error occurred' });
319→    }
320→
321→})
